```java
protected void computeCRIndicators(int rpyIdx, int crSize, int pySize, 
        int NCR_ALL, int[] NCR_RPY, int[][] NCR_CR_PY, int[] NCR_CR, 
        int[] NCR_CR_all, int[] NPYEARS_CR, int[] NCR_PY, int[] NCR, 
        CRIndicatorsUpdate updateCR) {

    // Berechne Perzentile einmalig
    PercentileResult percentiles = computePercentiles(NCR_CR_PY, crSize, pySize, NCR_PY);

    int noPYWithoutCR = (int) IntStream.range(0, pySize)
        .filter(i -> NCR_PY[i] == 0)
        .count();

    // Pro CR: Berechne Indikatoren
    for (int crIdx = 0; crIdx < crSize; crIdx++) {
        CRIndicatorValues indicators = calculateIndicatorsForCR(
            crIdx, rpyIdx, pySize, noPYWithoutCR, 
            NCR_ALL, NCR_RPY, NCR_CR, NCR_CR_all, NPYEARS_CR, 
            NCR_PY, NCR, NCR_CR_PY, percentiles);

        updateCR.update(crIdx, indicators.nPyears, indicators.pyearPerc, 
            indicators.percYr, indicators.percAll, indicators.nPct, 
            indicators.nPctAboveAverage, indicators.sequence, indicators.type);
    }
}

private CRIndicatorValues calculateIndicatorsForCR(int crIdx, int rpyIdx, int pySize, 
        int noPYWithoutCR, int NCR_ALL, int[] NCR_RPY, int[] NCR_CR, 
        int[] NCR_CR_all, int[] NPYEARS_CR, int[] NCR_PY, int[] NCR, 
        int[][] NCR_CR_PY, PercentileResult percentiles) {

    CRIndicatorValues result = new CRIndicatorValues();

    int[] typeCounters = new int[11];
    char[] sequence = new char[pySize];
    int[] nPct = new int[PERCENTAGE.values().length];
    int[] nPctAboveAverage = new int[PERCENTAGE.values().length];

    // Pro Jahr: Berechne Z-Score, Sequenz, Perzentil-Zugehörigkeit
    for (int pyIdx = 0; pyIdx < pySize; pyIdx++) {
        double expected = (1.0d * NCR_CR[crIdx] * NCR_PY[pyIdx]) / NCR[0];
        double zvalue = expected == 0 ? 0 
            : (NCR_CR_PY[crIdx][pyIdx] - expected) / Math.sqrt(expected);

        // Sequenz und Type-Zähler
        sequence[pyIdx] = getZValueSymbol(zvalue).label;
        updateTypeCounters(typeCounters, pyIdx, pySize, zvalue, NCR_CR_PY[crIdx][pyIdx]);

        // Perzentil-Position
        for (int b = 0; b < PERCENTAGE.values().length; b++) {
            if (percentiles.borders[pyIdx][b] < NCR_CR_PY[crIdx][pyIdx]) {
                nPct[b]++;
                if (zvalue > 1) {
                    nPctAboveAverage[b]++;
                }
            }
        }
    }

    // Berechne CR-Typen
    String typeLabel = determineCRTypes(typeCounters);

    result.nPyears = NPYEARS_CR[crIdx];
    result.pyearPerc = (double) NPYEARS_CR[crIdx] / (pySize - noPYWithoutCR);
    result.percYr = (double) NCR_CR_all[crIdx] / NCR_RPY[rpyIdx];
    result.percAll = (double) NCR_CR_all[crIdx] / NCR_ALL;
    result.nPct = nPct;
    result.nPctAboveAverage = nPctAboveAverage;
    result.sequence = new String(sequence);
    result.type = typeLabel;

    return result;
}

private void updateTypeCounters(int[] type, int pyIdx, int pySize, double zvalue, int citations) {
    type[0] += (zvalue < -1) ? 0 : 1;
    type[1] += ((pyIdx < 3) && (zvalue < -1)) ? 1 : 0;
    type[2] += ((pyIdx >= 3) && (zvalue > 1)) ? 1 : 0;
    type[3] += ((pyIdx < 3) && (zvalue > 1)) ? 1 : 0;
    type[4] += ((pyIdx < 4) && (zvalue <= 1)) ? 1 : 0;
    type[5] += ((pyIdx >= 4) && (zvalue > 1)) ? 1 : 0;
    type[6] += ((pySize - pyIdx <= 3) && (zvalue <= 1)) ? 1 : 0;
    type[7] += (citations > 0) ? 1 : 0;
    type[9] += (zvalue > 1) ? 1 : 0;
    type[10] += 1;
}

private String determineCRTypes(int[] type) {
    StringBuilder result = new StringBuilder();
    if ((type[1] >= 2) && (type[2] >= 1)) result.append("Sleeping beauty");
    if (((double) type[0] / type[10]) > 0.8 && ((double) type[7] / type[10]) > 0.8) {
        if (result.length() > 0) result.append(" + ");
        result.append("Constant performer");
    }
    if (type[3] >= 2) {
        if (result.length() > 0) result.append(" + ");
        result.append("Hot paper");
    }
    if ((type[4] >= 2) && (type[5] >= 2) && (type[6] > 1)) {
        if (result.length() > 0) result.append(" + ");
        result.append("Life cycle");
    }
    return result.toString();
}

