private void computePercentileForYear(int pyIdx, int rangeSize, int pySize, 
        int[][] NCR_CR_PY, int crSize, PercentileResult result) {
    int rangeStart = Math.max(0, pyIdx - rangeSize);
    int rangeEnd = Math.min(pySize - 1, pyIdx + rangeSize);

    // Sammle und sortiere mit CR-Index-Tracking
    int[] temp = new int[(rangeEnd - rangeStart + 1) * crSize];
    int[] crIndices = new int[temp.length];

    int pos = 0;
    for (int rIdx = rangeStart; rIdx <= rangeEnd; rIdx++) {
        for (int crIdx = 0; crIdx < crSize; crIdx++) {
            temp[pos] = NCR_CR_PY[crIdx][rIdx];
            crIndices[pos] = crIdx;
            pos++;
        }
    }

    // Sortiere nach Werten
    Integer[] order = IntStream.range(0, temp.length)
        .boxed()
        .sorted(Comparator.comparingInt(i -> temp[i]))
        .toArray(Integer[]::new);

    // Berechne kumulative Summen
    long[] prefixSum = new long[temp.length];
    if (temp.length > 0) {
        prefixSum[order[0]] = temp[order[0]];
        for (int i = 1; i < temp.length; i++) {
            prefixSum[order[i]] = prefixSum[order[i - 1]] + temp[order[i]];
        }
    }

    long totalSum = prefixSum.length > 0 ? prefixSum[order[temp.length - 1]] : 1;

    // Speichere Perzentil-Info
    for (PERCENTAGE perc : PERCENTAGE.values()) {
        int idx = Math.max(0, (int) Math.floor(perc.threshold * temp.length) - 1);
        result.borders[pyIdx][perc.ordinal()] = temp[order[idx]];
        result.cumulativeSums[pyIdx][perc.ordinal()] = prefixSum[order[idx]];
