        int[] NCR_CR_all, int[] NPYEARS_CR, int[] NCR_PY, int[] NCR, 
        int[][] NCR_CR_PY, PercentileResult percentiles) {

    CRIndicatorValues result = new CRIndicatorValues();

    int[] typeCounters = new int[11];
    char[] sequence = new char[pySize];
    int[] nPct = new int[PERCENTAGE.values().length];
    int[] nPctAboveAverage = new int[PERCENTAGE.values().length];

    // Pro Jahr: Berechne Z-Score, Sequenz, Perzentil-Zugehörigkeit
    for (int pyIdx = 0; pyIdx < pySize; pyIdx++) {
        double expected = (1.0d * NCR_CR[crIdx] * NCR_PY[pyIdx]) / NCR[0];
        double zvalue = expected == 0 ? 0 
            : (NCR_CR_PY[crIdx][pyIdx] - expected) / Math.sqrt(expected);

        // Sequenz und Type-Zähler
        sequence[pyIdx] = getZValueSymbol(zvalue).label;
        updateTypeCounters(typeCounters, pyIdx, pySize, zvalue, NCR_CR_PY[crIdx][pyIdx]);

        // Perzentil-Position
        for (int b = 0; b < PERCENTAGE.values().length; b++) {
            if (percentiles.borders[pyIdx][b] < NCR_CR_PY[crIdx][pyIdx]) {
                nPct[b]++;
                if (zvalue > 1) {
                    nPctAboveAverage[b]++;
                }
            }
        }
