            crIdx, rpyIdx, yearData, percentiles, rpyStats.NCR_ALL, rpyStats.NCR_RPY);

        CRType_MM cr = yearData.crList.get(crIdx);
        storeIndicatorsInCR(cr, indicators);
    }
}

private CRYearData collectCRYearData(int rpy, IntRange range_PY, List<CRType_MM> crList) {
    int firstPY = Math.max(rpy, range_PY.getMin());
    int lastPY = range_PY.getMax();

    if (lastPY < firstPY) return null;

    int pySize = lastPY - firstPY + 1;
    int crSize = crList.size();

    CRYearData data = new CRYearData();
    data.NCR_CR_PY = new int[crSize][pySize];
    data.NCR_CR = new int[crSize];
    data.NCR_CR_all = new int[crSize];
    data.NPYEARS_CR = new int[crSize];
    data.NCR_PY = new int[pySize];
    data.crList = crList;

    // Sammle Daten pro CR und Jahr
    for (int crIdx = 0; crIdx < crSize; crIdx++) {
        CRType_MM cr = crList.get(crIdx);
        data.NCR_CR_all[crIdx] = cr.getN_CR();

        cr.getPub()
            .filter(pub -> pub.getPY() != null && pub.getPY() >= firstPY && pub.getPY() <= lastPY)
            .forEach(pub -> {
                int pyIdx = pub.getPY() - firstPY;

                if (data.NCR_CR_PY[crIdx][pyIdx] == 0) {
                    data.NPYEARS_CR[crIdx]++;
                }

                data.NCR_CR_PY[crIdx][pyIdx]++;
                data.NCR_CR[crIdx]++;
                data.NCR_PY[pyIdx]++;
                data.NCR_total++;
            });
    }

    return data;
}

private PercentileResult computeAllPercentiles(CRYearData yearData) {
    PercentileResult result = new PercentileResult();
    int pySize = yearData.NCR_PY.length;
    int crSize = yearData.crList.size();

    result.borders = new int[pySize][PERCENTAGE.values().length];
    result.cumulativeSums = new long[pySize][PERCENTAGE.values().length];
    result.cumulativePct = new double[pySize][PERCENTAGE.values().length];

    int rangeSize = getNpctRange();

    for (int pyIdx = 0; pyIdx < pySize; pyIdx++) {
        computePercentileForYear(pyIdx, rangeSize, pySize, crSize, 
            yearData.NCR_CR_PY, result);
    }

    return result;
}

private void computePercentileForYear(int pyIdx, int rangeSize, int pySize, 
        int crSize, int[][] NCR_CR_PY, PercentileResult result) {

    int rangeStart = Math.max(0, pyIdx - rangeSize);
    int rangeEnd = Math.min(pySize - 1, pyIdx + rangeSize);

    // Sammle Werte mit CR-Index
    int[] temp = new int[(rangeEnd - rangeStart + 1) * crSize];
    int pos = 0;

    for (int rIdx = rangeStart; rIdx <= rangeEnd; rIdx++) {
        for (int crIdx = 0; crIdx < crSize; crIdx++) {
            temp[pos++] = NCR_CR_PY[crIdx][rIdx];
        }
    }

    // Sortiere und berechne kumulative Summen
    Arrays.sort(temp);

    long[] prefixSum = new long[temp.length];
    if (temp.length > 0) {
        prefixSum[0] = temp[0];
        for (int i = 1; i < temp.length; i++) {
            prefixSum[i] = prefixSum[i - 1] + temp[i];
        }
    }

    long totalSum = prefixSum.length > 0 ? prefixSum[temp.length - 1] : 1;

    // Speichere Perzentil-Werte
    for (PERCENTAGE perc : PERCENTAGE.values()) {
        int idx = Math.max(0, (int) Math.floor(perc.threshold * temp.length) - 1);
        result.borders[pyIdx][perc.ordinal()] = temp[idx];
        result.cumulativeSums[pyIdx][perc.ordinal()] = prefixSum[idx];
        result.cumulativePct[pyIdx][perc.ordinal()] = 100.0 * prefixSum[idx] / totalSum;
    }
}

private CRIndicatorValues calculateCRIndicators(int crIdx, int rpyIdx, 
        CRYearData yearData, PercentileResult percentiles, 
        int NCR_ALL, int[] NCR_RPY) {

    CRIndicatorValues result = new CRIndicatorValues();
    int pySize = yearData.NCR_PY.length;

    int[] typeCounters = new int[11];
    char[] sequence = new char[pySize];
    int[] nPct = new int[PERCENTAGE.values().length];
    int[] nPctAboveAverage = new int[PERCENTAGE.values().length];

    // Berechne pro Jahr
    for (int pyIdx = 0; pyIdx < pySize; pyIdx++) {
        double expected = yearData.NCR_total == 0 ? 0 
            : (1.0d * yearData.NCR_CR[crIdx] * yearData.NCR_PY[pyIdx]) / yearData.NCR_total;

        double zvalue = expected == 0 ? 0 
            : (yearData.NCR_CR_PY[crIdx][pyIdx] - expected) / Math.sqrt(expected);

        // Sequenz
        sequence[pyIdx] = getZValueSymbol(zvalue).label;

        // Type-Counter aktualisieren
        updateTypeCounters(typeCounters, pyIdx, pySize, zvalue, 
            yearData.NCR_CR_PY[crIdx][pyIdx]);

        // Perzentil-Position prüfen
        for (int b = 0; b < PERCENTAGE.values().length; b++) {
            if (percentiles.borders[pyIdx][b] < yearData.NCR_CR_PY[crIdx][pyIdx]) {
                nPct[b]++;
                if (zvalue > 1) {
                    nPctAboveAverage[b]++;
                }
            }
        }
    }

    // Berechne finale Indikatoren
    int noPYWithoutCR = (int) IntStream.range(0, pySize)
        .filter(i -> yearData.NCR_PY[i] == 0)
        .count();

    result.nPyears = yearData.NPYEARS_CR[crIdx];
    result.pyearPerc = (double) yearData.NPYEARS_CR[crIdx] / (pySize - noPYWithoutCR);
    result.percYr = (double) yearData.NCR_CR_all[crIdx] / NCR_RPY[0];  // rpyIdx = 0 vereinfacht
    result.percAll = (double) yearData.NCR_CR_all[crIdx] / NCR_ALL;
    result.nPct = nPct;
    result.nPctAboveAverage = nPctAboveAverage;
    result.sequence = new String(sequence);
    result.type = determineCRTypes(typeCounters);

    return result;
}

private void updateTypeCounters(int[] type, int pyIdx, int pySize, 
        double zvalue, int citations) {
    type[0] += (zvalue < -1) ? 0 : 1;
    type[1] += ((pyIdx < 3) && (zvalue < -1)) ? 1 : 0;
    type[2] += ((pyIdx >= 3) && (zvalue > 1)) ? 1 : 0;
    type[3] += ((pyIdx < 3) && (zvalue > 1)) ? 1 : 0;
    type[4] += ((pyIdx < 4) && (zvalue <= 1)) ? 1 : 0;
    type[5] += ((pyIdx >= 4) && (zvalue > 1)) ? 1 : 0;
    type[6] += ((pySize - pyIdx <= 3) && (zvalue <= 1)) ? 1 : 0;
    type[7] += (citations > 0) ? 1 : 0;
    type[9] += (zvalue > 1) ? 1 : 0;
    type[10] += 1;
}

private String determineCRTypes(int[] type) {
    StringBuilder result = new StringBuilder();

    if ((type[1] >= 2) && (type[2] >= 1)) {
        result.append("Sleeping beauty");
    }
    if (((double) type[0] / type[10]) > 0.8 && ((double) type[7] / type[10]) > 0.8) {
        if (result.length() > 0) result.append(" + ");
        result.append("Constant performer");
    }
    if (type[3] >= 2) {
        if (result.length() > 0) result.append(" + ");
        result.append("Hot paper");
    }
    if ((type[4] >= 2) && (type[5] >= 2) && (type[6] > 1)) {
        if (result.length() > 0) result.append(" + ");
        result.append("Life cycle");
    }

    return result.toString();
}

private CRTable.ZValueSymbol getZValueSymbol(double zvalue) {
    if (zvalue > 1) return CRTable.ZValueSymbol.PLUS;
    if (zvalue < -1) return CRTable.ZValueSymbol.MINUS;
    return CRTable.ZValueSymbol.ZERO;
}

private void storeIndicatorsInCR(CRType_MM cr, CRIndicatorValues indicators) {
    cr.setN_PYEARS(indicators.nPyears);
    cr.setPYEAR_PERC(indicators.pyearPerc);
    cr.setPERC_YR(indicators.percYr);
    cr.setPERC_ALL(indicators.percAll);
    cr.setN_PCT(indicators.nPct);
    cr.setN_PCT_AboveAverage(indicators.nPctAboveAverage);
    cr.setSEQUENCE(indicators.sequence);
    cr.setTYPE(indicators.type);
}

private void logPerformance(long startTime, long startMemory) {
    long endTime = System.currentTimeMillis();
    long endMemory = Runtime.getRuntime().totalMemory();

    double timeSec = (endTime - startTime) / 1000.0;
    double memMB = (endMemory - startMemory) / (1024.0 * 1024.0);

    CRELogger.get().logInfo("Indicator computation completed");
    CRELogger.get().logInfo(String.format("Time: %.2f seconds, Memory: %.2f MB", timeSec, memMB));
}
```

### Vorteile dieser Refaktorierung

✅ **Klare Trennung**: Datensammlung → Perzentile → Indikatoren → Speichern  
✅ **Bessere Fehlerbehandlung**: Jedem Schritt eine Methode  
✅ **Testbarkeit**: Jede Methode isoliert testbar  
✅ **Wiederverwendbarkeit**: Methoden können separat genutzt werden  
✅ **Performance**: Keine redundanten Berechnungen  
✅ **Wartbarkeit**: Klare Datenflüsse, aussagekräftige Variablennamen  

