private void computePercentileForYear(int pyIdx, int rangeSize, int pySize, 
        int crSize, int[][] NCR_CR_PY, PercentileResult result) {

    int rangeStart = Math.max(0, pyIdx - rangeSize);
    int rangeEnd = Math.min(pySize - 1, pyIdx + rangeSize);

    // Sammle Werte mit CR-Index für CP_IN-Berechnung
    Integer[] crIndicesWithValues = new Integer[(rangeEnd - rangeStart + 1) * crSize];
    int[] temp = new int[(rangeEnd - rangeStart + 1) * crSize];
    int pos = 0;

    for (int rIdx = rangeStart; rIdx <= rangeEnd; rIdx++) {
        for (int crIdx = 0; crIdx < crSize; crIdx++) {
            crIndicesWithValues[pos] = crIdx;
            temp[pos] = NCR_CR_PY[crIdx][rIdx];
            pos++;
        }
    }

    // Sortiere und berechne kumulative Summen
    Integer[] sortedIndices = new Integer[temp.length];
    for (int i = 0; i < temp.length; i++) {
        sortedIndices[i] = i;
    }

    // Sortiere Indizes nach temp-Werten
    Arrays.sort(sortedIndices, (i, j) -> Integer.compare(temp[i], temp[j]));

    long[] prefixSum = new long[temp.length];
    long totalSum = 0;
    for (int i = 0; i < sortedIndices.length; i++) {
        totalSum += temp[sortedIndices[i]];
        prefixSum[i] = totalSum;
    }

    // CP_IN pro CR: Prozentsatz der kumulativen Summe bis zu diesem CR
    if (result.crCumulativePct == null) {
        result.crCumulativePct = new double[crSize];
    }
    if (result.crRankings == null) {
        result.crRankings = new int[crSize];
    }

    for (int i = 0; i < sortedIndices.length; i++) {
        int originalIdx = sortedIndices[i];
        int crIdx = crIndicesWithValues[originalIdx];
        double cpInValue = totalSum > 0 ? (100.0 * prefixSum[i] / totalSum) : 0.0;
        result.crCumulativePct[crIdx] = Math.max(result.crCumulativePct[crIdx], cpInValue);
        result.crRankings[crIdx] = i;
    }

    // Speichere Perzentil-Grenzen
    for (PERCENTAGE perc : PERCENTAGE.values()) {
        int idx = Math.max(0, (int) Math.floor(perc.threshold * temp.length) - 1);
        result.borders[pyIdx][perc.ordinal()] = temp[idx];
    }
}
