        double cpInValue = totalSum > 0 ? (100.0 * prefixSum[i] / totalSum) : 0.0;
        result.crCumulativePct[crIdx] = Math.max(result.crCumulativePct[crIdx], cpInValue);
        result.crRankings[crIdx] = i;
    }

    // Speichere Perzentil-Grenzen
    for (PERCENTAGE perc : PERCENTAGE.values()) {
        int idx = Math.max(0, (int) Math.floor(perc.threshold * temp.length) - 1);
        result.borders[pyIdx][perc.ordinal()] = temp[idx];
    }
}
```

